import React from 'react';
import { Routes, Route, Link } from 'react-router-dom';
import './App.css';

// ===== COMPONENTS =====
const Header = () => {
  return (
    <header className="header">
      <nav className="navbar">
        <Link to="/" className="logo">Bike<span>Rental</span></Link>
        <ul className="nav-links">
          <li><Link to="/">Home</Link></li>
          <li><Link to="/bikes">Bikes</Link></li>
          <li><Link to="/manage-bookings">Manage Bookings</Link></li>
          <li><Link to="/contact">Contact</Link></li>
          <li><Link to="/terms">Terms</Link></li>
        </ul>
      </nav>
    </header>
  );
};

const Footer = () => {
  return (
    <footer className="footer">
      <div className="footer-content">
        <div className="footer-section">
          <h3>BikeRental</h3>
          <p>Your trusted partner for bike rentals. Quality bikes, affordable prices, and excellent service.</p>
        </div>
        <div className="footer-section">
          <h3>Quick Links</h3>
          <ul>
            <li><Link to="/">Home</Link></li>
            <li><Link to="/bikes">Bikes</Link></li>
            <li><Link to="/manage-bookings">Manage Bookings</Link></li>
            <li><Link to="/contact">Contact</Link></li>
          </ul>
        </div>
        <div className="footer-section">
          <h3>Contact Info</h3>
          <p>📞 +91 9876543210</p>
          <p>✉️ info@bikerental.com</p>
          <p>📍 123 Bike Street, City, State 560001</p>
        </div>
      </div>
      <div className="footer-bottom">
        <p>&copy; 2024 BikeRental. All rights reserved.</p>
      </div>
    </footer>
  );
};

const BikeCard = ({ bike }) => {
  return (
    <div className="card bike-card">
      <div className="bike-image">
        🏍️
      </div>
      <div className="bike-details">
        <h3 className="bike-name">{bike?.name || 'Bike Name'}</h3>
        <span className="bike-category">{bike?.category || 'Category'}</span>
        <div className="bike-price">₹{bike?.price || '0'}/day</div>
        <Link to={`/booking/${bike?.id || '1'}`} className="btn btn-primary">
          Book Now
        </Link>
      </div>
    </div>
  );
};

const BookingForm = () => {
  return (
    <div className="card">
      <div className="card-header">
        <h3>Booking Information</h3>
      </div>
      <div className="card-body">
        <p>Booking form will be implemented here</p>
        <button className="btn btn-primary">Submit Booking</button>
      </div>
    </div>
  );
};

const BookingSummary = () => {
  return (
    <div className="booking-summary">
      <h3>Booking Summary</h3>
      <div className="summary-item">
        <span>Total Amount:</span>
        <span>₹1200.00</span>
      </div>
    </div>
  );
};

const BookingsTable = () => {
  return (
    <div className="table-container">
      <p>Bookings table will be implemented here</p>
    </div>
  );
};

const Modal = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()}>
        <div className="modal-header">
          <h3 className="modal-title">{title}</h3>
          <button className="modal-close" onClick={onClose}>×</button>
        </div>
        <div className="modal-body">
          {children}
        </div>
      </div>
    </div>
  );
};

// ===== PAGES =====
const Home = () => {
  return (
    <div>
      <section className="hero">
        <div className="hero-content">
          <h1>Ride Your Adventure With Premium Bikes</h1>
          <p>Discover the perfect bike for your journey. From city commutes to mountain adventures.</p>
          <div className="hero-buttons">
            <Link to="/bikes" className="btn btn-secondary">Browse Bikes</Link>
            <Link to="/contact" className="btn btn-outline">Contact Us</Link>
          </div>
        </div>
      </section>

      <section className="section">
        <div className="section-title">
          <h2>Featured Bikes</h2>
          <p>Check out our most popular bikes</p>
        </div>
        <div className="grid grid-3">
          <BikeCard bike={{ name: 'Sports Bike', category: 'Sports', price: 1000, id: 1 }} />
          <BikeCard bike={{ name: 'Cruiser Bike', category: 'Cruiser', price: 1500, id: 2 }} />
          <BikeCard bike={{ name: 'Commuter Bike', category: 'Commuter', price: 700, id: 3 }} />
        </div>
      </section>
    </div>
  );
};

const Bikes = () => {
  const bikes = [
    { id: 1, name: 'Apache RTR 160', category: 'Sports', price: 1000 },
    { id: 2, name: 'Bajaj Pulsar', category: 'Sports', price: 500 },
    { id: 3, name: 'Royal Enfield Classic 350', category: 'Cruiser', price: 1500 },
